namespace GHB.DP2.SourceGenerators.Templates;

public static class SoftDeleteTemplate
{
    private const string Template =
        """
        // <auto-generated />
        using LanguageExt;
        using static LanguageExt.Prelude;

        {NAMESPACE_START}
        {INDENT}partial class {CLASS_NAME}
        {INDENT}{
        {INDENT}    /// <summary>
        {INDENT}    /// Gets a value indicating whether this entity is marked as deleted.
        {INDENT}    /// </summary>
        {INDENT}    public bool IsDeleted { get; private set; }

        {INDENT}    /// <summary>
        {INDENT}    /// Marks this entity as deleted by setting the IsDeleted property to true.
        {INDENT}    /// </summary>
        {INDENT}    /// <returns>A unit value indicating the operation completed.</returns>
        {INDENT}    public Unit Delete()
        {INDENT}    {
        {INDENT}        this.IsDeleted = true;
        {INDENT}        return unit;
        {INDENT}    }
        {INDENT}}
        {NAMESPACE_END}
        """;

    public static string Generate(string? namespaceName, string className)
    {
        var indent = string.IsNullOrEmpty(namespaceName) ? "" : "    ";

        var result = Template
                     .Replace("{CLASS_NAME}", className)
                     .Replace("{INDENT}", indent)
                     .Replace("{NAMESPACE_START}",
                         string.IsNullOrEmpty(namespaceName) ? "" : $"namespace {namespaceName}\n{{")
                     .Replace("{NAMESPACE_END}",
                         string.IsNullOrEmpty(namespaceName) ? "" : "}");

        return result;
    }
}